const config = {
  "previewFeatures": [],
  "clientVersion": "7.6.0",
  "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
  "activeProvider": "postgresql",
  "inlineSchema": "// =============================================================\n// USER ACTIVITY (Watchlist and Notifications)\n// =============================================================\n\n// =============================================================\n// WATCHLIST\n// =============================================================\n\nmodel WatchlistItem {\n  id        String   @id @default(cuid())\n  userId    String\n  mediaId   String\n  createdAt DateTime @default(now())\n\n  user  User  @relation(fields: [userId], references: [id], onDelete: Cascade)\n  media Media @relation(fields: [mediaId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, mediaId])\n  @@map(\"watchlist_item\")\n}\n\n// =============================================================\n// NOTIFICATIONS \n// =============================================================\n\nmodel Notification {\n  id        String   @id @default(cuid())\n  userId    String\n  personId  String?\n  title     String\n  body      String\n  link      String? // deep link in the app\n  isRead    Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId, isRead])\n  @@map(\"notification\")\n}\n\n// =============================================================\n// AUTHENTICATION\n// Better Auth core tables — required by the library\n// =============================================================\n\nmodel User {\n  id            String    @id @default(uuid(7))\n  name          String\n  email         String    @unique\n  emailVerified Boolean   @default(false)\n  image         String?\n  role          Role      @default(USER)\n  banned        Boolean   @default(false)\n  gender        Gender?\n  banReason     String?\n  banExpires    DateTime?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  // Better Auth relations\n  sessions Session[]\n  accounts Account[]\n\n  // App relations\n  reviews       Review[]\n  reviewLikes   ReviewLike[]\n  comments      Comment[]\n  watchlist     WatchlistItem[]\n  purchases     Purchase[]\n  notifications Notification[]\n  subscription  Subscription[]\n\n  @@map(\"user\")\n}\n\nmodel Session {\n  id             String   @id @default(uuid(7))\n  expiresAt      DateTime\n  token          String   @unique\n  ipAddress      String?\n  userAgent      String?\n  userId         String\n  impersonatedBy String?\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"session\")\n}\n\nmodel Account {\n  id                    String    @id @default(uuid(7))\n  accountId             String\n  providerId            String\n  userId                String\n  accessToken           String?\n  refreshToken          String?\n  idToken               String?\n  accessTokenExpiresAt  DateTime?\n  refreshTokenExpiresAt DateTime?\n  scope                 String?\n  password              String? // hashed — used for email/password provider\n  createdAt             DateTime  @default(now())\n  updatedAt             DateTime  @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"account\")\n}\n\nmodel Verification {\n  id         String    @id @default(uuid(7))\n  identifier String\n  value      String\n  expiresAt  DateTime\n  createdAt  DateTime? @default(now())\n  updatedAt  DateTime? @updatedAt\n\n  @@map(\"verification\")\n}\n\n// =============================================================\n// BASE - Configuration and Enums\n// =============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum Role {\n  USER\n  ADMIN\n  SUPER_ADMIN\n}\n\nenum MediaType {\n  MOVIE\n  SERIES\n}\n\nenum MediaStatus {\n  PUBLISHED\n  DRAFT\n  ARCHIVED\n}\n\nenum ReviewStatus {\n  PENDING\n  PUBLISHED\n  UNPUBLISHED\n}\n\nenum PricingTier {\n  FREE\n  PREMIUM\n}\n\nenum SubscriptionPlan {\n  MONTHLY\n  YEARLY\n}\n\nenum SubscriptionStatus {\n  PENDING\n  ACTIVE\n  CANCELLED\n  EXPIRED\n  PAST_DUE\n}\n\nenum PurchaseType {\n  RENTAL\n  ONE_TIME_BUY\n}\n\nenum PaymentStatus {\n  PENDING\n  COMPLETED\n  FAILED\n  REFUNDED\n}\n\nenum Gender {\n  MALE\n  FEMALE\n  OTHER\n}\n\nenum StreamingPlatFormEnum {\n  NETFLIX\n  AMAZON_PRIME\n  DISNEY_PLUS\n  HBO_MAX\n  HULU\n  APPLE_TV\n  YOUTUBE\n  OTHER\n}\n\n// =============================================================\n// MEDIA LIBRARY\n// =============================================================\n\nmodel Genre {\n  id          String       @id @default(uuid(7))\n  name        String       @unique // e.g. \"Action\", \"Drama\", \"Sci-Fi\"\n  slug        String       @unique\n  createdAt   DateTime     @default(now())\n  updatedAt   DateTime     @updatedAt\n  isDeleted   Boolean      @default(false)\n  mediaGenres MediaGenre[]\n\n  @@map(\"genre\")\n}\n\nmodel StreamingPlatform {\n  id        String   @id @default(uuid(7))\n  name      String   @unique // e.g. \"Netflix\", \"Disney+\", \"Amazon Prime\"\n  slug      String   @unique\n  logoUrl   String?\n  createdAt DateTime @default(now())\n\n  mediaLinks MediaStreamingLink[]\n\n  @@map(\"streaming_platform\")\n}\n\nmodel Media {\n  id                String                 @id @default(uuid(7))\n  title             String\n  slug              String                 @unique\n  synopsis          String\n  type              MediaType\n  releaseYear       Int\n  director          String?\n  posterUrl         String?\n  backdropUrl       String?\n  trailerUrl        String? // YouTube embed URL\n  streamingUrl      String? // direct streaming/YouTube link\n  pricingTier       PricingTier            @default(PREMIUM)\n  status            MediaStatus            @default(PUBLISHED)\n  isFeatured        Boolean?               @default(false)\n  isEditorPick      Boolean?               @default(false)\n  streamingPlatFrom StreamingPlatFormEnum? @default(YOUTUBE)\n\n  // Aggregated rating cache — updated via background job or trigger\n  avgRating    Float?\n  totalRatings Int?   @default(0)\n  totalReviews Int?   @default(0)\n\n  //renting or buying options\n  rentPrice Decimal? @db.Decimal(10, 2)\n  buyPrice  Decimal? @db.Decimal(10, 2)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  genres         MediaGenre[]\n  cast           MediaCast[]\n  streamingLinks MediaStreamingLink[]\n  reviews        Review[]\n  watchlistItems WatchlistItem[]\n  purchases      Purchase[]\n\n  @@index([status, pricingTier])\n  @@index([releaseYear])\n  @@index([avgRating])\n  @@map(\"media\")\n}\n\n// Many-to-many: Media <-> Genre\nmodel MediaGenre {\n  mediaId String\n  genreId String\n\n  media Media @relation(fields: [mediaId], references: [id], onDelete: Cascade)\n  genre Genre @relation(fields: [genreId], references: [id], onDelete: Cascade)\n\n  @@id([mediaId, genreId])\n  @@map(\"media_genre\")\n}\n\n// Many-to-many: Media <-> StreamingPlatform (with optional deep link)\nmodel MediaStreamingLink {\n  id         String  @id @default(cuid())\n  mediaId    String\n  platformId String\n  deepLink   String? // platform-specific URL\n\n  media    Media             @relation(fields: [mediaId], references: [id], onDelete: Cascade)\n  platform StreamingPlatform @relation(fields: [platformId], references: [id], onDelete: Cascade)\n\n  @@unique([mediaId, platformId])\n  @@map(\"media_streaming_link\")\n}\n\n// =============================================================\n// ACTORS & CASTING (Many-to-Many)\n// =============================================================\n\n// 1. The Real-Life Actor (They only exist here once)\nmodel Actor {\n  id        String   @id @default(uuid(7))\n  name      String\n  photoUrl  String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // This links the actor to all the movies they played in\n  roles MediaCast[]\n\n  @@map(\"actor\")\n}\n\n// 2. The Join Table (The Bridge connecting Media and Actor)\nmodel MediaCast {\n  id        String  @id @default(uuid(7))\n  mediaId   String\n  actorId   String\n  character String? // e.g., \"Dom Cobb\" or \"Batman\"\n  order     Int     @default(0) // Display order on the frontend\n\n  media Media @relation(fields: [mediaId], references: [id], onDelete: Cascade)\n  actor Actor @relation(fields: [actorId], references: [id], onDelete: Cascade)\n\n  // This prevents accidentally adding the exact same actor playing the exact same character in a movie twice\n  @@unique([mediaId, actorId, character])\n  // Indexes make finding an actor's movies (or a movie's actors) blazing fast\n  @@index([mediaId])\n  @@index([actorId])\n  @@map(\"media_cast\")\n}\n\n// =============================================================\n// REVIEWS AND COMMENTS\n// =============================================================\n\nmodel Review {\n  id          String        @id @default(uuid(7))\n  userId      String\n  mediaId     String\n  rating      Int // 1–10\n  content     String\n  hasSpoiler  Boolean?      @default(false)\n  status      ReviewStatus? @default(PENDING)\n  publishedAt DateTime?     @default(now())\n  adminNote   String? // reason for unpublishing\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  user     User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n  media    Media        @relation(fields: [mediaId], references: [id], onDelete: Cascade)\n  tags     ReviewTag[]\n  likes    ReviewLike[]\n  comments Comment[]\n\n  // One user, one review per title\n  @@unique([userId, mediaId])\n  @@index([mediaId, status])\n  @@index([status])\n  @@map(\"review\")\n}\n\nmodel Tag {\n  id   String @id @default(cuid())\n  name String @unique // e.g. \"classic\", \"underrated\", \"family-friendly\"\n  slug String @unique\n\n  reviewTags ReviewTag[]\n\n  @@map(\"tag\")\n}\n\n// Many-to-many: Review <-> Tag\nmodel ReviewTag {\n  reviewId String\n  tagId    String\n\n  review Review @relation(fields: [reviewId], references: [id], onDelete: Cascade)\n  tag    Tag    @relation(fields: [tagId], references: [id], onDelete: Cascade)\n\n  @@id([reviewId, tagId])\n  @@map(\"review_tag\")\n}\n\nmodel ReviewLike {\n  id        String   @id @default(uuid(7))\n  userId    String\n  reviewId  String\n  createdAt DateTime @default(now())\n\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  review Review @relation(fields: [reviewId], references: [id], onDelete: Cascade)\n\n  // One like per user per review\n  @@unique([userId, reviewId])\n  @@map(\"review_like\")\n}\n\n// =============================================================\n// COMMENTS  (nested threads via self-relation)\n// =============================================================\n\nmodel Comment {\n  id        String   @id @default(uuid(7))\n  userId    String\n  reviewId  String\n  parentId  String? // null = top-level; set = reply\n  content   String\n  isHidden  Boolean  @default(false)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  user    User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  review  Review    @relation(fields: [reviewId], references: [id], onDelete: Cascade)\n  parent  Comment?  @relation(\"CommentReplies\", fields: [parentId], references: [id])\n  replies Comment[] @relation(\"CommentReplies\")\n\n  @@index([reviewId])\n  @@map(\"comment\")\n}\n\n// =============================================================\n// SUBSCRIPTIONS & PAYMENTS\n// =============================================================\n\n// model Purchase {\n//   id              String        @id @default(uuid(7))\n//   userId          String\n//   subscriptionId  String?\n//   type            PurchaseType\n//   amount          Decimal       @db.Decimal(10, 2)\n//   currency        String        @default(\"USD\")\n//   paymentStatus   PaymentStatus @default(PENDING)\n//   paymentProvider String?       // \"stripe\" | \"sslcommerz\"\n//   providerTxnId   String?       @unique\n//   providerPayload Json?         // raw webhook payload for audit\n//   refundedAt      DateTime?\n//   createdAt       DateTime      @default(now())\n//   updatedAt       DateTime      @updatedAt\n\n//   user         User          @relation(fields: [userId], references: [id], onDelete: Cascade)\n//   subscription Subscription? @relation(fields: [subscriptionId], references: [id])\n\n//   @@index([userId])\n//   @@index([paymentStatus])\n//   @@map(\"purchase\")\n// }\n\n// =============================================================\n// PURCHASES & RENTALS (PAY-PER-VIEW)\n// =============================================================\n\nmodel Purchase {\n  id     String @id @default(uuid(7))\n  userId String\n\n  // 1. Link the purchase directly to the Movie/Series they are buying\n  mediaId String\n\n  // 2. This will be either \"RENTAL\" or \"ONE_TIME_BUY\"\n  type PurchaseType\n\n  amount   Decimal @db.Decimal(10, 2)\n  currency String  @default(\"USD\")\n\n  // 3. If they rent it, this stores when their 48-hour access expires\n  accessTimeStartedAt DateTime?\n  accessExpiresAt     DateTime?\n\n  paymentStatus   PaymentStatus @default(PENDING)\n  paymentProvider String? // \"stripe\" | \"sslcommerz\"\n  providerTxnId   String?       @unique\n  providerPayload Json? // raw webhook payload for audit\n  refundedAt      DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  user  User  @relation(fields: [userId], references: [id], onDelete: Cascade)\n  media Media @relation(fields: [mediaId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([mediaId])\n  @@index([paymentStatus])\n  @@map(\"purchase\")\n}\n\nmodel Subscription {\n  id     String             @id @default(uuid(7))\n  userId String             @unique\n  status SubscriptionStatus @default(PENDING) // ACTIVE, PAST_DUE, CANCELED\n\n  // 🟢 The exact billing cycle dates (Updated by Stripe/Webhook every month)\n  currentPeriodStart DateTime\n  currentPeriodEnd   DateTime\n\n  // 🟢 Pro-tip: If they cancel, they still get to watch until the 'End' date\n  cancelAtPeriodEnd Boolean @default(false)\n\n  // Tracking details\n  paymentProvider  String? // \"stripe\", \"sslcommerz\"\n  providerSubId    String? @unique\n  stripeCustomerId String?\n\n  createdAt DateTime @default(now()) // When they first subscribed ever\n  updatedAt DateTime @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"subscription\")\n}\n"
}

